<div class="form-group"><label>Descrição</label><input type="text" class="form-control" name="descricao" id="edit_descricao" required></div>
<div class="row"><div class="col-md-6"><div class="form-group"><label>Tipo</label><select class="form-control" name="tipo" id="edit_tipo"><option value="RECEITA">Receita</option><option value="DESPESA">Despesa</option></select></div></div><div class="col-md-6"><div class="form-group"><label>Categoria</label><input type="text" class="form-control" name="categoria" id="edit_categoria"></div></div></div>
<div class="row"><div class="col-md-4"><div class="form-group"><label>Valor</label><input type="number" step="0.01" class="form-control" name="valor" id="edit_valor" required></div></div><div class="col-md-4"><div class="form-group"><label>Data</label><input type="date" class="form-control" name="data_lancamento" id="edit_data_lancamento"></div></div><div class="col-md-4"><div class="form-group"><label>Conta</label><input type="text" class="form-control" name="conta_bancaria" id="edit_conta_bancaria"></div></div></div>
