<div class="form-group"><label>Data Conciliação</label><input type="date" class="form-control" name="data_conciliacao" id="edit_data_conciliacao"></div>
<div class="form-group"><label>Status</label><select class="form-control" name="status" id="edit_status"><option value="PENDENTE">Pendente</option><option value="CONCILIADO">Conciliado</option></select></div>
