</div><div class="modal-footer"><button type="button" class="btn btn-secondary" data-dismiss="modal">Cancelar</button><button type="submit" class="btn btn-primary">Atualizar</button></div></form></div></div></div>

<script>
$(document).ready(function() {
    if (!$.fn.DataTable.isDataTable('#tbl_conciliacao')) $('#tbl_conciliacao').DataTable({ "info": true, "searching": true, "paging": true, "pageLength": 15, "order": [[4, 'desc']], "language": { "url": "//cdn.datatables.net/plug-ins/9dcbecd42ad/i18n/Portuguese.json" } });
    $('.btn-edit').on('click', function() {
        $.getJSON('<?= base_url(); ?>conciliacao/get/' + $(this).data('id'), function(data) {
            $('#edit_id').val(data.idlancamento); $('#edit_descricao').val(data.descricao);
            $('#edit_tipo').val(data.tipo); $('#edit_categoria').val(data.categoria); $('#edit_valor').val(data.valor);
            if (data.data_lancamento) $('#edit_data_lancamento').val(data.data_lancamento);
            $('#edit_conta_bancaria').val(data.conta_bancaria); $('#edit_documento').val(data.documento);
            if (data.data_conciliacao) $('#edit_data_conciliacao').val(data.data_conciliacao);
            $('#edit_status').val(data.status); $('#edit_observacoes').val(data.observacoes);
            $('#modalEdit').modal('show');
        });
    });
});
</script>
